    confirmTransaction (transactionId);
}

function confirmTransaction (uint transactionId) public ownerExists (msg.sender) transactionExists (transactionId) notConfirmed (transactionId, msg.sender) {
    confirmations [transactionId] [msg.sender] = true;
    Confirmation (msg.sender, transactionId);
    executeTransaction (transactionId);
}

function revokeConfirmation (uint transactionId) public ownerExists (msg.sender) confirmed (transactionId, msg.sender) notExecuted (transactionId) {
    confirmations [transactionId] [msg.sender] = false;
    Revocation (msg.sender, transactionId);
}

function executeTransaction (uint transactionId) public ownerExists (msg.sender) confirmed (transactionId, msg.sender) notExecuted (transactionId) {
    if (isConfirmed (transactionId)) {
        Transaction storage txn = transactions [transactionId];
        txn.executed = true;
        if (external_call (txn.destination, txn.value, txn.data.length, txn.data)) Execution (transactionId);
        else {
            ExecutionFailure (transactionId);
            txn.executed = false;
        }
    }
}

function external_call (address destination, uint value, uint dataLength, bytes data) private returns (bool) {
    bool result;
    assembly {let x : = mload (0x40) let d : = add (data, 32) result : = call (sub (gas, 34710), destination, value, d, dataLength, x, 0)} return result;
}

function isConfirmed (uint transactionId) public constant returns (bool) {
    uint count = 0;
    for (uint i = 0; i < owners.length; i + +) {
        if (confirmations [transactionId] [owners [i]]) count + = 1;
        if (count = = required) return true;
    }
}

function addTransaction (address destination, uint value, bytes data) internal notNull (destination) returns (uint transactionId) {
    transactionId = transactionCount;
    transactions [transactionId] = Transaction ({destination : destination, value : value, data : data, executed : false});
    transactionCount + = 1;
    Submission (transactionId);
}

function getConfirmationCount (uint transactionId) public constant returns (uint count) {
    for (uint i = 0; i < owners.length; i + +) if (confirmations [transactionId] [owners [i]]) count + = 1;
}

function getTransactionCount (bool pending, bool executed) public constant returns (uint count) {
    for (uint i = 0; i < transactionCount; i + +) if (pending & & ! transactions [i].executed | | executed & & transactions [i].executed) count + = 1;
}

