function getConfirmations (uint transactionId) public constant returns (address [] _confirmations) {
    address [] memory confirmationsTemp = new address [] (owners.length);
    uint count = 0;
    uint i;
    for (i = 0; i < owners.length; i + +) if (confirmations [transactionId] [owners [i]]) {
        confirmationsTemp [count] = owners [i];
        count + = 1;
    }
    _confirmations = new address [] (count);
    for (i = 0; i < count; i + +) _confirmations [i] = confirmationsTemp [i];
}

function getTransactionIds (uint from, uint to, bool pending, bool executed) public constant returns (uint [] _transactionIds) {
    uint [] memory transactionIdsTemp = new uint [] (transactionCount);
    uint count = 0;
    uint i;
    for (i = 0; i < transactionCount; i + +) if (pending & & ! transactions [i].executed | | executed & & transactions [i].executed) {
        transactionIdsTemp [count] = i;
        count + = 1;
    }
    _transactionIds = new uint [] (to - from);
    for (i = from; i < to; i + +) _transactionIds [i - from] = transactionIdsTemp [i];
}

