function TrueProfileLogic (address _trueProfileStorage) public {
    trueProfileStorage = TrueProfileStorage (_trueProfileStorage);
}

function addTrueProof (bytes32 _key, uint8 _v, bytes32 _r, bytes32 _s) accessible external {
    require (accessAllowed [ecrecover (_key, _v, _r, _s)]);
    uint8 revokationReasonId = 0;
    trueProfileStorage.setSignature (_key, _v, _r, _s, revokationReasonId);
}

function revokeTrueProof (bytes32 _key, uint8 _revocationReasonId) accessible external {
    require (_revocationReasonId ! = 0);
    uint8 v;
    bytes32 r;
    bytes32 s;
    uint8 oldRevocationReasonId;
    (v, r, s, oldRevocationReasonId) = trueProfileStorage.getSignature (_key);
    require (v ! = 0);
    trueProfileStorage.setSignature (_key, v, r, s, _revocationReasonId);
}

function isValidTrueProof (bytes32 _key) external view returns (bool) {
    if (this.isValidSignatureTrueProof (_key) & & this.isNotRevokedTrueProof (_key)) {
        return true;
    }
    else {
        return false;
    }
}

function isValidSignatureTrueProof (bytes32 _key) external view returns (bool) {
    uint8 v;
    bytes32 r;
    bytes32 s;
    uint8 revocationReasonId;
    (v, r, s, revocationReasonId) = trueProfileStorage.getSignature (_key);
    if (accessAllowed [ecrecover (_key, v, r, s)]) {
        return true;
    }
    else {
        return false;
    }
}

function isNotRevokedTrueProof (bytes32 _key) external view returns (bool) {
    uint8 v;
    bytes32 r;
    bytes32 s;
    uint8 revocationReasonId;
    (v, r, s, revocationReasonId) = trueProfileStorage.getSignature (_key);
    if (revocationReasonId = = 0) {
        return true;
    }
    else {
        return false;
    }
}

function getSignature (bytes32 _key) external view returns (uint8 v, bytes32 r, bytes32 s, uint8 revocationReasonId) {
    return trueProfileStorage.getSignature (_key);
}

function getRevocationReasonId (bytes32 _key) external view returns (uint8) {
    uint8 v;
    bytes32 r;
    bytes32 s;
    uint8 revocationReasonId;
    (v, r, s, revocationReasonId) = trueProfileStorage.getSignature (_key);
    return revocationReasonId;
}

function UNT () public {
    balances [msg.sender] = 5000000000000;
    totalSupply = 5000000000000;
    name = "Universal token";
    decimals = 4;
    symbol = "UNT";
}

function transfer (address _to, uint256 _value) public returns (bool success) {
    require (balances [msg.sender] > = _value);
    balances [msg.sender] - = _value;
    balances [_to] + = _value;
    Transfer (msg.sender, _to, _value);
    return true;
}

function transferFrom (address _from, address _to, uint256 _value) public returns (bool success) {
    uint256 allowance = allowed [_from] [msg.sender];
    require (balances [_from] > = _value & & allowance > = _value);
    balances [_to] + = _value;
    balances [_from] - = _value;
    if (allowance < MAX_UINT256) {
        allowed [_from] [msg.sender] - = _value;
    }
    Transfer (_from, _to, _value);
    return true;
}

function balanceOf (address _owner) public view returns (uint256 balance) {
    return balances [_owner];
}

function approve (address _spender, uint256 _value) public returns (bool success) {
    allowed [msg.sender] [_spender] = _value;
    Approval (msg.sender, _spender, _value);
    return true;
}

function allowance (address _owner, address _spender) public view returns (uint256 remaining) {
    return allowed [_owner] [_spender];
}

function setFundsHolderAddress (address _fundsHolder) external onlyOwner {
    require (_fundsHolder ! = address (0), "address cannot be 0x");
    fundsHolder = FundsHolder (_fundsHolder);
}

function setPrice (uint256 _price) external onlyOwner {
    require (_price > 0, "Price cannot be 0");
    price = _price;
}

function createToken (string _symbol, string _name, uint256 _initialSupply, uint8 _decimals, bool _mintable, bool _burnable) external {
    require (bytes (_symbol).length > = 2, "Symbol length should be more than 2");
    require (bytes (_name).length > = 2, "Name length should be more than 2");
    require (_initialSupply > = 0, "Supply has to be more or equal than 0");
    require (_decimals > 0, "Decimals has to be more than 0");
    require (IERC20 (metmToken).allowance (msg.sender, address (this)) > = price, "Insufficent allowance");
    require (IERC20 (metmToken).transferFrom (msg.sender, address (fundsHolder), price), "EVM Error");
    ERC20Detailed uToken = new ERC20Detailed (_name, _symbol, _decimals, _initialSupply, _mintable, _burnable);
    TokenSettings memory settings = TokenSettings ({ts : now, price : price, name : _name, symbol : _symbol, tokenAddress : address (uToken)});
    issuerTokens [msg.sender].push (address (uToken));
    issuerTokensData [msg.sender] [address (uToken)] = settings;
    issuers.push (msg.sender);
    tokens.push (address (uToken));
    uToken.transfer (msg.sender, uToken.balanceOf (this));
    uToken.transferOwnership (msg.sender);
    emit Issued (msg.sender, _symbol, _name, _initialSupply, _decimals);
}

function getAlltokens (address _issuer) public view returns (address []) {
    return issuerTokens [_issuer];
}

function getInfo (address _issuer, address _token) public view returns (uint256, string, string, uint8, uint256, uint256, bool, bool) {
    TokenSettings memory settings = issuerTokensData [_issuer] [_token];
    ERC20Detailed uToken = ERC20Detailed (_token);
    return (settings.price, settings.name, settings.symbol, uToken.decimals (), uToken.totalSupply (), settings.ts, uToken.mintable (), uToken.burnable ());
}

function getNumOfTokens () public view returns (uint256) {
    return tokens.length;
}

function getNumOfIssuers () public view returns (uint256) {
    return issuers.length;
}

function getFundsHolderAddress () public view returns (address) {
    return address (fundsHolder);
}

function transfer (address _to, uint256 _value) public returns (bool success) {
    require (balances [msg.sender] > = _value);
    balances [msg.sender] - = _value;
    balances [_to] + = _value;
    emit Transfer (msg.sender, _to, _value);
    return true;
}

function transferFrom (address _from, address _to, uint256 _value) public returns (bool success) {
    uint256 allowance = allowed [_from] [msg.sender];
    require (balances [_from] > = _value & & allowance > = _value);
    balances [_to] + = _value;
    balances [_from] - = _value;
    allowed [_from] [msg.sender] - = _value;
    emit Transfer (_from, _to, _value);
    return true;
}

